    const error = new Error('stream error');

    // Source that emits no data and ends with an actual error
    const source = (end: any, cb: Function) => {
      if (end) return cb(end);
      cb(error, null); // end with an actual error, no data
    };

    const sink = find((data: any) => false, (err: any, data: any) => {
      expect(err).toBe(error);
      expect(data).toBeNull();
      done();
    });

    sink(source);
