import find from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/find.js"

describe('find', () => {
  it('should pass actual errors to callback when no match found', (done) => {
    const error = new Error('stream error');
    let callCount = 0;

    const source = (end: any, cb: Function) => {
      callCount++;
      if (end) return cb(end);
      if (callCount === 1) {
        cb(null, 1); // emit one item that doesn't match
      } else {
        cb(error); // end with error
      }
    };

    const sink = find((data: any) => data === 999, (err: any, data: any) => {
      expect(err).toBe(error); // original passes error, mutant passes null
      expect(data).toBeNull();
      done();
    });

    sink(source);
  });
});
```

